const rawOutput =
$input.first().json.output ||
$input.first().json.text ||
'{}';

let parsed;

try {
const cleanOutput = rawOutput
.replace(/`json/g, '')
    .replace(/`/g, '')
.trim();

parsed = JSON.parse(cleanOutput);

} catch (error) {

parsed = {
brandCheckPassed: false,
error: error.message,
rawOutput
};

}

return [{ json: parsed }];

const pptxgen = require('pptxgenjs');

const input = $input.first().json;

const pptx = new pptxgen();

pptx.author = 'AI Agent';
pptx.company = 'GreatBots';

pptx.layout = 'LAYOUT_WIDE';

const slide = pptx.addSlide();

slide.background = {
color: 'FFFFFF'
};

slide.addText(input.headline || 'Campaign Headline', {
x: 0.5,
y: 0.5,
w: 11,
h: 0.8,
fontSize: 24,
bold: true,
color: '1F4E78'
});

slide.addText(
(input.bodyPoints || []).join('\n\n'),
{
x: 0.7,
y: 1.5,
w: 11,
h: 3.5,
fontSize: 16,
color: '333333',
breakLine: false
}
);

slide.addText(`CTA: ${input.cta}`, {
x: 0.7,
y: 5.4,
w: 8,
h: 0.5,
fontSize: 18,
bold: true,
color: '008000'
});

slide.addText(
`Reach: ${input.metrics?.reach}
Engagement: ${input.metrics?.engagement}
Conversion: ${input.metrics?.conversion}
ROI: ${input.metrics?.roi}`,
{
x: 8,
y: 5,
w: 4,
h: 1,
fontSize: 12,
color: '555555'
}
);

const fileName = `${Date.now()}.pptx`;

const filePath =
`C:\\Users\\GreatBots\\Downloads\\files1\\${fileName}`;

await pptx.writeFile({
fileName: filePath
});

return [
{
json: {
...input,
pptPath: filePath,
fileName
}
}
];
